   144→    public KotlinSpringServerCodegen() {
   145→        super();
   146→
   147→        modifyFeatureSet(features -> features
   148→                .includeDocumentationFeatures(DocumentationFeature.Readme)
   149→                .wireFormatFeatures(EnumSet.of(WireFormatFeature.JSON, WireFormatFeature.XML))
   150→                .securityFeatures(EnumSet.of(
   151→                        SecurityFeature.BasicAuth,
   152→                        SecurityFeature.ApiKey,
   153→                        SecurityFeature.OAuth2_Implicit,
   154→                        SecurityFeature.OAuth2_ClientCredentials,
   155→                        SecurityFeature.OAuth2_Password,
   156→                        SecurityFeature.OAuth2_AuthorizationCode
   157→                ))
   158→                .excludeGlobalFeatures(
   159→                        GlobalFeature.XMLStructureDefinitions,
   160→                        GlobalFeature.Callbacks,
   161→                        GlobalFeature.LinkObjects,
   162→                        GlobalFeature.ParameterStyling
   163→                )
   164→                .includeSchemaSupportFeatures(
   165→                        SchemaSupportFeature.Polymorphism
   166→                )
   167→                .includeParameterFeatures(
   168→                        ParameterFeature.Cookie
   169→                )
   170→        );
   171→
   172→        reservedWords.addAll(VARIABLE_RESERVED_WORDS);
