   199→        addOption(SERVER_PORT, "configuration the port in which the sever is to run on", serverPort);
   200→        addOption(CodegenConstants.MODEL_PACKAGE, "model package for generated code", modelPackage);
   201→        addOption(CodegenConstants.API_PACKAGE, "api package for generated code", apiPackage);
   202→        addSwitch(EXCEPTION_HANDLER, "generate default global exception handlers (not compatible with reactive. enabling reactive will disable exceptionHandler )", exceptionHandler);
   203→        addSwitch(GRADLE_BUILD_FILE, "generate a gradle build file using the Kotlin DSL", gradleBuildFile);
   204→        addSwitch(USE_SWAGGER_UI, "Open the OpenApi specification in swagger-ui. Will also import and configure needed dependencies", useSwaggerUI);
   205→        addSwitch(SERVICE_INTERFACE, "generate service interfaces to go alongside controllers. In most " +
