   207→                "Useful to help facilitate the generation gap pattern", serviceInterface);
   208→        addSwitch(SERVICE_IMPLEMENTATION, "generate stub service implementations that extends service " +
   209→                "interfaces. If this is set to true service interfaces will also be generated", serviceImplementation);
   210→        addSwitch(USE_BEANVALIDATION, "Use BeanValidation API annotations to validate data types", useBeanValidation);
   211→        addSwitch(SKIP_DEFAULT_INTERFACE, "Whether to skip generation of default implementations for interfaces (Api interfaces or Delegate interfaces depending on the delegatePattern option)", skipDefaultInterface);
   212→        addSwitch(REACTIVE, "use coroutines for reactive behavior", reactive);
   213→        addSwitch(INTERFACE_ONLY, "Whether to generate only API interface stubs without the server files.", interfaceOnly);
   214→        addSwitch(USE_FEIGN_CLIENT_URL, "Whether to generate Feign client with url parameter.", useFeignClientUrl);
   215→        addSwitch(DELEGATE_PATTERN, "Whether to generate the server files using the delegate pattern", delegatePattern);
   216→        addSwitch(USE_TAGS, "Whether to use tags for creating interface and controller class names", useTags);
   217→        addSwitch(BEAN_QUALIFIERS, "Whether to add fully-qualifier class names as bean qualifiers in @Component and " +
   218→                "@RestController annotations. May be used to prevent bean names clash if multiple generated libraries" +
   219→                " (contexts) added to single project.", beanQualifiers);
   220→        addSwitch(USE_SPRING_BOOT3, "Generate code and provide dependencies for use with Spring Boot 3.x. (Use jakarta instead of javax in imports). Enabling this option will also enable `useJakartaEe`.", useSpringBoot3);
   221→        addSwitch(USE_FLOW_FOR_ARRAY_RETURN_TYPE, "Whether to use Flow for array/collection return types when reactive is enabled. If false, will use List instead.", useFlowForArrayReturnType);
   222→        supportedLibraries.put(SPRING_BOOT, "Spring-boot Server application.");
