   742→    @Override
   743→    public void addOperationToGroup(String tag, String resourcePath, Operation operation, CodegenOperation co, Map<String, List<CodegenOperation>> operations) {
   744→        if (library.equals(SPRING_BOOT) && !useTags) {
   745→            String basePath = resourcePath;
   746→            if (basePath.startsWith("/")) {
   747→                basePath = basePath.substring(1);
   748→            }
   749→            int pos = basePath.indexOf("/");
   750→            if (pos > 0) {
   751→                basePath = basePath.substring(0, pos);
   752→            }
   753→
   754→            if (basePath.isEmpty()) {
   755→                basePath = "default";
   756→            } else {
   757→                co.subresourceOperation = !co.path.isEmpty();
   758→            }
   759→            List<CodegenOperation> opList = operations.computeIfAbsent(basePath, k -> new ArrayList<>());
   760→            opList.add(co);
   761→            co.baseName = basePath;
   762→        } else {
   763→            super.addOperationToGroup(tag, resourcePath, operation, co, operations);
   764→        }
   765→    }
