   767→    @Override
   768→    public void preprocessOpenAPI(OpenAPI openAPI) {
   769→        super.preprocessOpenAPI(openAPI);
   770→
   771→        if (!additionalProperties.containsKey(TITLE)) {
   772→            // The purpose of the title is for:
   773→            // - README documentation
   774→            // - The spring.application.name
   775→            // - And linking the @RequestMapping
   776→            // This is an additional step we add when pre-processing the API spec, if
   777→            // there is no user configuration set for the `title` of the project,
   778→            // we try build and normalise a title from the API spec itself.
   779→            String title = openAPI.getInfo().getTitle();
   780→
   781→            // Drop any API suffix
   782→            if (title != null) {
   783→                title = title.trim().replace(" ", "-");
   784→                if (title.toUpperCase(Locale.ROOT).endsWith("API"))
   785→                    title = title.substring(0, title.length() - 3);
   786→
   787→                this.title = camelize(sanitizeName(title), LOWERCASE_FIRST_LETTER);
   788→            }
   789→            additionalProperties.put(TITLE, this.title);
   790→        }
   791→
   792→        if (!additionalProperties.containsKey(SERVER_PORT)) {
   793→            URL url = URLPathUtils.getServerURL(openAPI, serverVariableOverrides());
   794→            this.additionalProperties.put(SERVER_PORT, URLPathUtils.getPort(url, 8080));
   795→        }
   796→
   797→        // TODO: Handle tags
   798→    }
