   800→    @Override
   801→    public void postProcessModelProperty(CodegenModel model, CodegenProperty property) {
   802→        super.postProcessModelProperty(model, property);
   803→
   804→        if ("null".equals(property.example)) {
   805→            property.example = null;
   806→        }
   807→
   808→        //Add imports for Jackson
   809→        if (!Boolean.TRUE.equals(model.isEnum)) {
   810→            model.imports.add("JsonProperty");
   811→            if (Boolean.TRUE.equals(model.hasEnums)) {
   812→                model.imports.add("JsonValue");
   813→                model.imports.add("JsonCreator");
   814→            }
   815→        } else {
   816→            //Needed imports for Jackson's JsonCreator
   817→            if (additionalProperties.containsKey("jackson")) {
   818→                model.imports.add("JsonCreator");
   819→            }
   820→        }
   821→
   822→        if (model.discriminator != null && additionalProperties.containsKey("jackson")) {
   823→            model.imports.addAll(Arrays.asList("JsonSubTypes", "JsonTypeInfo"));
   824→        }
   825→    }
