   832→        List<Map<String, String>> imports = objs.getImports();
   833→
   834→        objs.getModels().stream()
   835→                .map(ModelMap::getModel)
   836→                .filter(cm -> Boolean.TRUE.equals(cm.isEnum) && cm.allowableValues != null)
   837→                .forEach(cm -> {
   838→                    cm.imports.add(importMapping.get("JsonValue"));
   839→                    cm.imports.add(importMapping.get("JsonCreator"));
   840→                    cm.imports.add(importMapping.get("JsonProperty"));
   841→                    Map<String, String> itemJsonValue = new HashMap<>();
   842→                    itemJsonValue.put("import", importMapping.get("JsonValue"));
   843→                    imports.add(itemJsonValue);
   844→                    Map<String, String> itemJsonCreator = new HashMap<>();
   845→                    itemJsonCreator.put("import", importMapping.get("JsonCreator"));
   846→                    imports.add(itemJsonCreator);
   847→                    Map<String, String> itemJsonProperty = new HashMap<>();
   848→                    itemJsonProperty.put("import", importMapping.get("JsonProperty"));
   849→                    imports.add(itemJsonProperty);
   850→                });
   851→
   852→        return objs;
   853→    }
   854→
   855→    @Override
   856→    public OperationsMap postProcessOperationsWithModels(OperationsMap objs, List<ModelMap> allModels) {
   857→        OperationMap operations = objs.getOperations();
   858→        if (operations != null) {
   859→            List<CodegenOperation> ops = operations.getOperation();
   860→            ops.forEach(operation -> {
   861→                List<CodegenResponse> responses = operation.responses;
   862→                if (responses != null) {
   863→                    responses.forEach(resp -> {
   864→
   865→                        if ("0".equals(resp.code)) {
   866→                            resp.code = "200";
   867→                        }
   868→
   869→                        // This is necessary in case 'modelMutable' is enabled,
   870→                        // to prevent Spring Request handlers from being generated with
   871→                        // the ApiResponse annotation configured with the Mutable container type.
   872→                        // See https://github.com/OpenAPITools/openapi-generator/pull/11154#discussion_r793108068
   873→                        resp.baseType = getNonMutableContainerTypeIfNeeded(resp.baseType);
   874→
   875→                        doDataTypeAssignment(resp.dataType, new DataTypeAssigner() {
   876→                            @Override
   877→                            public void setReturnType(final String returnType) {
   878→                                resp.dataType = returnType;
   879→                            }
   880→
   881→                            @Override
   882→                            public void setReturnContainer(final String returnContainer) {
   883→                                resp.containerType = returnContainer;
   884→                            }
   885→                        });
   886→                    });
   887→                }
   888→
   889→                final List<CodegenParameter> allParams = operation.allParams;
   890→                if (allParams != null) {
   891→                    allParams.forEach(param ->
   892→                            // This is necessary in case 'modelMutable' is enabled,
   893→                            // to prevent Spring Request handlers from being generated with
   894→                            // parameters using their Mutable container types.
   895→                            // See https://github.com/OpenAPITools/openapi-generator/pull/11154#discussion_r793094727
   896→                            param.dataType = getNonMutableContainerTypeIfNeeded(param.dataType));
   897→                }
   898→
   899→                doDataTypeAssignment(operation.returnType, new DataTypeAssigner() {
   900→
   901→                    @Override
   902→                    public void setReturnType(final String returnType) {
   903→                        operation.returnType = returnType;
   904→                    }
   905→
   906→                    @Override
   907→                    public void setReturnContainer(final String returnContainer) {
   908→                        operation.returnContainer = returnContainer;
   909→                    }
   910→                });
   911→//                if(implicitHeaders){
   912→//                    removeHeadersFromAllParams(operation.allParams);
   913→//                }
   914→            });
   915→        }
   916→
   917→        return objs;
   918→    }
   919→
   920→    @Override
   921→    public Map<String, Object> postProcessSupportingFileData(Map<String, Object> objs) {
   922→        generateYAMLSpecFile(objs);
   923→        return objs;
   924→    }
   925→
   926→
   927→    private String getNonMutableContainerTypeIfNeeded(String type) {
   928→        if (type != null && type.contains("kotlin.collections.Mutable")) {
   929→            return type.replaceAll("kotlin\\.collections\\.Mutable", "kotlin.collections.");
   930→        }
   931→        return type;
   932→    }
   933→
   934→    private static String sanitizeDirectory(String in) {
   935→        return in.replace(".", File.separator);
   936→    }
   937→
   938→    // TODO could probably be made more generic, and moved to the `mustache` package if required by other components.
   939→    private static class EscapeLambda implements Mustache.Lambda {
   940→        private final String from;
   941→        private final String to;
   942→
   943→        EscapeLambda(final String from, final String to) {
   944→            this.from = from;
   945→            this.to = Matcher.quoteReplacement(to);
   946→        }
   947→
   948→        @Override
   949→        public void execute(Template.Fragment fragment, Writer writer) throws IOException {
   950→            writer.write(fragment.execute().replaceAll(from, to));
   951→        }
   952→    }
   953→
   954→    /**
   955→     * Output the proper model name (capitalized).
   956→     * In case the name belongs to the TypeSystem it won't be renamed.
   957→     *
   958→     * @param name the name of the model
   959→     * @return capitalized model name
   960→     */
   961→    @Override
   962→    public String toModelName(final String name) {
   963→        // Allow for explicitly configured spring.*
   964→        if (name.startsWith("org.springframework.")) {
   965→            return name;
   966→        }
   967→        return super.toModelName(name);
   968→    }
   969→
   970→    /**
   971→     * Check the type to see if it needs import the library/module/package
   972→     *
   973→     * @param type name of the type
   974→     * @return true if the library/module/package of the corresponding type needs to be imported
   975→     */
   976→    @Override
   977→    protected boolean needToImport(String type) {
   978→        // provides extra protection against improperly trying to import language primitives and java types
   979→        return !type.startsWith("org.springframework.") && super.needToImport(type);
   980→    }
   981→
   982→    public RequestMappingMode getRequestMappingMode() {
   983→        return requestMappingMode;
   984→    }
   985→
   986→    public void setRequestMappingMode(RequestMappingMode requestMappingMode) {
   987→        this.requestMappingMode = requestMappingMode;
   988→    }
   989→
   990→    @Override
   991→    public List<VendorExtension> getSupportedVendorExtensions() {
   992→        List<VendorExtension> extensions = super.getSupportedVendorExtensions();
   993→        extensions.add(VendorExtension.X_ACCEPTS);
   994→        extensions.add(VendorExtension.X_CLASS_EXTRA_ANNOTATION);
   995→        extensions.add(VendorExtension.X_CONTENT_TYPE);
   996→        extensions.add(VendorExtension.X_DISCRIMINATOR_VALUE);
   997→        extensions.add(VendorExtension.X_FIELD_EXTRA_ANNOTATION);
   998→        extensions.add(VendorExtension.X_PATTERN_MESSAGE);
   999→        return extensions;
  1000→    }
