   558→    /**
   559→     * Return the sanitized variable name for enum
   560→     *
   561→     * @param value    enum variable name
   562→     * @param datatype data type
   563→     * @return the sanitized variable name for enum
   564→     */
   565→    @Override
   566→    public String toEnumVarName(String value, String datatype) {
   567→        if (enumNameMapping.containsKey(value)) {
   568→            return enumNameMapping.get(value);
   569→        }
   570→
   571→        String modified;
   572→        if (value.isEmpty()) {
   573→            modified = "EMPTY";
   574→        } else {
   575→            modified = value.replaceAll("-", "_");
   576→            modified = sanitizeKotlinSpecificNames(modified);
   577→        }
   578→
   579→        switch (getEnumPropertyNaming()) {
   580→            case original:
   581→                // NOTE: This is provided as a last-case allowance, but will still result in reserved words being escaped.
   582→                modified = value;
   583→                break;
   584→            case camelCase:
   585→                // NOTE: Removes hyphens and underscores
   586→                modified = camelize(modified, LOWERCASE_FIRST_LETTER);
   587→                break;
   588→            case PascalCase:
   589→                // NOTE: Removes hyphens and underscores
   590→                String result = camelize(modified);
   591→                modified = titleCase(result);
   592→                break;
   593→            case snake_case:
   594→                // NOTE: Removes hyphens
   595→                modified = underscore(modified);
   596→                break;
   597→            case UPPERCASE:
   598→                modified = underscore(modified).toUpperCase(Locale.ROOT);
   599→                break;
   600→        }
   601→
   602→        if (reservedWords.contains(modified)) {
   603→            return escapeReservedWord(modified);
   604→        }
   605→        // NOTE: another sanitize because camelize can create an invalid name
   606→        return sanitizeKotlinSpecificNames(modified);
   607→    }
