   639→    /**
   640→     * Output the proper model name (capitalized).
   641→     * In case the name belongs to the TypeSystem it won't be renamed.
   642→     *
   643→     * @param name the name of the model
   644→     * @return capitalized model name
   645→     */
   646→    @Override
   647→    public String toModelName(final String name) {
   648→        // obtain the name from modelNameMapping directly if provided
   649→        if (modelNameMapping.containsKey(name)) {
   650→            return modelNameMapping.get(name);
   651→        }
   652→
   653→        // memoization
   654→        if (schemaKeyToModelNameCache.containsKey(name)) {
   655→            return schemaKeyToModelNameCache.get(name);
   656→        }
   657→
   658→        // Allow for explicitly configured kotlin.* and java.* types
   659→        if (name.startsWith("kotlin.") || name.startsWith("java.")) {
   660→            return name;
   661→        }
   662→
   663→        // If schemaMapping contains name, assume this is a legitimate model name.
   664→        if (schemaMapping.containsKey(name)) {
   665→            return schemaMapping.get(name);
   666→        }
   667→
   668→        // TODO review importMapping below as we've added schema mapping support
   669→        // If importMapping contains name, assume this is a legitimate model name.
   670→        if (importMapping.containsKey(name)) {
   671→            return importMapping.get(name);
   672→        }
   673→
   674→        String modifiedName = name.replaceAll("\\.", "").replaceAll("-", "_");
   675→
   676→        String nameWithPrefixSuffix = sanitizeKotlinSpecificNames(modifiedName);
   677→        if (!StringUtils.isEmpty(modelNamePrefix)) {
   678→            // add '_' so that model name can be camelized correctly
   679→            nameWithPrefixSuffix = modelNamePrefix + "_" + nameWithPrefixSuffix;
   680→        }
   681→
   682→        if (!StringUtils.isEmpty(modelNameSuffix)) {
   683→            // add '_' so that model name can be camelized correctly
   684→            nameWithPrefixSuffix = nameWithPrefixSuffix + "_" + modelNameSuffix;
   685→        }
   686→
   687→        // Camelize name of nested properties
   688→        modifiedName = camelize(nameWithPrefixSuffix);
   689→
   690→        // model name cannot use reserved keyword, e.g. return
   691→        if (isReservedWord(modifiedName)) {
   692→            final String modelName = "Model" + modifiedName;
   693→            LOGGER.warn("{} (reserved word) cannot be used as model name. Renamed to {}", modifiedName, modelName);
   694→            return modelName;
   695→        }
   696→
   697→        // model name starts with number
   698→        if (modifiedName.matches("^\\d.*")) {
   699→            final String modelName = "Model" + modifiedName; // e.g. 200Response => Model200Response (after camelize)
   700→            LOGGER.warn("{} (model name starts with number) cannot be used as model name. Renamed to {}", name,
   701→                    modelName);
   702→            return modelName;
   703→        }
   704→
   705→        schemaKeyToModelNameCache.put(name, titleCase(modifiedName));
   706→        return schemaKeyToModelNameCache.get(name);
   707→    }
