   716→    public String toOperationId(String operationId) {
   717→        // throw exception if method name is empty
   718→        if (StringUtils.isEmpty(operationId))
   719→            throw new RuntimeException("Empty method/operation name (operationId) not allowed");
   720→
   721→        operationId = camelize(sanitizeName(operationId), LOWERCASE_FIRST_LETTER);
   722→
   723→        // method name cannot use reserved keyword, e.g. return
   724→        if (isReservedWord(operationId)) {
   725→            String newOperationId = camelize("call_" + operationId, LOWERCASE_FIRST_LETTER);
   726→            LOGGER.warn("{} (reserved word) cannot be used as method name. Renamed to {}", operationId, newOperationId);
