   745→    /**
   746→     * Sanitize against Kotlin specific naming conventions, which may differ from those required by {@link DefaultCodegen#sanitizeName}.
   747→     *
   748→     * @param name string to be sanitize
   749→     * @return sanitized string
   750→     */
   751→    private String sanitizeKotlinSpecificNames(final String name) {
   752→        String word = name;
   753→        for (Map.Entry<String, String> specialCharacters : specialCharReplacements.entrySet()) {
   754→            word = replaceSpecialCharacters(word, specialCharacters);
   755→        }
   756→
   757→        // Fallback, replace unknowns with underscore.
   758→        word = Pattern.compile("\\W+", Pattern.UNICODE_CHARACTER_CLASS).matcher(word).replaceAll("_");
   759→        if (word.matches("\\d.*")) {
   760→            word = "_" + word;
   761→        }
   762→
   763→        // _, __, and ___ are reserved in Kotlin. Treat all names with only underscores consistently, regardless of count.
   764→        if (word.matches("^_*$")) {
   765→            word = word.replaceAll("\\Q_\\E", "Underscore");
   766→        }
   767→
   768→        return word;
   769→    }
   770→
   771→    private String replaceSpecialCharacters(String word, Map.Entry<String, String> specialCharacters) {
   772→        String specialChar = specialCharacters.getKey();
   773→        String replacementChar = specialCharacters.getValue();
   774→        // Underscore is the only special character we'll allow
   775→        if (!specialChar.equals("_") && word.contains(specialChar)) {
   776→            return replaceCharacters(word, specialChar, replacementChar);
   777→        }
   778→        return word;
   779→    }
   780→
   781→    private String replaceCharacters(String word, String oldValue, String newValue) {
   782→        if (!word.contains(oldValue)) {
   783→            return word;
   784→        }
   785→        if (word.equals(oldValue)) {
   786→            return newValue;
   787→        }
   788→        int i = word.indexOf(oldValue);
   789→        String start = word.substring(0, i);
   790→        String end = recurseOnEndOfWord(word, oldValue, newValue, i);
   791→        return start + newValue + end;
   792→    }
   793→
   794→    private String recurseOnEndOfWord(String word, String oldValue, String newValue, int lastReplacedValue) {
   795→        String end = word.substring(lastReplacedValue + 1);
   796→        if (!end.isEmpty()) {
   797→            end = titleCase(end);
   798→            end = replaceCharacters(end, oldValue, newValue);
   799→        }
   800→        return end;
   801→    }
