   915→
   916→        if (name.toLowerCase(Locale.ROOT).matches("^_*class$")) {
   917→            return "propertyClass";
   918→        }
   919→
   920→        if ("_".equals(name)) {
   921→            name = "_u";
   922→        }
   923→
   924→        // if it's all upper case, do nothing
   925→        if (name.matches("^[A-Z0-9_]*$")) {
   926→            return name;
   927→        }
   928→
   929→        if (startsWithTwoUppercaseLetters(name)) {
   930→            name = name.substring(0, 2).toLowerCase(Locale.ROOT) + name.substring(2);
   931→        }
   932→
   933→        // If name contains special chars -> replace them.
   934→        if ((name.chars().anyMatch(character -> specialCharReplacements.containsKey(String.valueOf((char) character))))) {
   935→            List<String> allowedCharacters = new ArrayList<>();
   936→            allowedCharacters.add("_");
   937→            allowedCharacters.add("$");
   938→            name = escape(name, specialCharReplacements, allowedCharacters, "_");
