  1045→    private String toArrayDefaultValue(CodegenProperty cp, Schema schema) {
  1046→        if (schema.getDefault() != null) {
  1047→            String arrInstantiationType = ModelUtils.isSet(schema) ? "set" : "arrayList";
  1048→
  1049→            if (!(schema.getDefault() instanceof ArrayNode)) {
  1050→                return null;
  1051→            }
  1052→            ArrayNode _default = (ArrayNode) schema.getDefault();
  1053→            if (_default.isEmpty()) {
  1054→                return arrInstantiationType + "Of()";
  1055→            }
  1056→
  1057→            StringBuilder defaultContent = new StringBuilder();
  1058→            Schema<?> itemsSchema = ModelUtils.getSchemaItems(schema);
  1059→            _default.elements().forEachRemaining((element) -> {
  1060→                String defaultValue = element.asText();
  1061→                if (defaultValue != null) {
  1062→                    if (cp.items.getIsEnumOrRef()) {
  1063→                        String className = cp.items.datatypeWithEnum;
  1064→                        String enumVarName = toEnumVarName(defaultValue, cp.items.dataType);
  1065→                        defaultContent.append(className).append(".").append(enumVarName).append(",");
  1066→                    } else {
  1067→                        itemsSchema.setDefault(defaultValue);
  1068→                        defaultValue = toDefaultValue(cp, itemsSchema);
  1069→                        defaultContent.append(defaultValue).append(",");
  1070→                    }
  1071→                }
  1072→            });
  1073→            defaultContent.deleteCharAt(defaultContent.length() - 1); // remove trailing comma
  1074→            return arrInstantiationType + "Of(" + defaultContent + ")";
  1075→        }
  1076→        return null;
  1077→    }
