        // Spring conversion uses Enum.valueOf by default; generated enum should provide fromString delegating to forValue.
        assertFileContains(
                Paths.get(outputPath + "/src/main/kotlin/org/openapitools/model/TestEnumSpec.kt"),
                "@JvmStatic",
                "fun fromString(value: kotlin.String): TestEnumSpec",
                "return forValue(value)"
        );

        // and controller should invoke TestEnumSpec.fromString for query params
        assertFileContains(
                Paths.get(outputPath + "/src/main/kotlin/org/openapitools/api/DefaultApiController.kt"),
                "TestEnumSpec.fromString"
        );
    }

