        File output = Files.createTempDirectory("test").toFile().getCanonicalFile();
        output.deleteOnExit();
        String outputPath = output.getAbsolutePath().replace('\\\\', '/');

        KotlinSpringServerCodegen codegen = new KotlinSpringServerCodegen();
        codegen.setOutputDir(output.getAbsolutePath());
        codegen.additionalProperties().put(CodegenConstants.ENUM_PROPERTY_NAMING, "UPPERCASE");

        new DefaultGenerator().opts(new ClientOptInput()
                        .openAPI(TestUtils.parseSpec("src/test/resources/3_0/kotlin/issue_kotlin_spring_enum_queryparam_nondefault_naming.yaml"))
                        .config(codegen))
                .generate();

        assertFileContains(
                Paths.get(outputPath + "/src/main/kotlin/org/openapitools/model/TestEnumSpec.kt"),
                "fun forValue(value: kotlin.String): TestEnumSpec",
                "values().first"
        );

        // Spring conversion uses Enum.valueOf by default; generated enum should provide fromString delegating to forValue.
        assertFileContains(
                Paths.get(outputPath + "/src/main/kotlin/org/openapitools/model/TestEnumSpec.kt"),
                "@JvmStatic",
                "fun fromString(value: kotlin.String): TestEnumSpec",
                "return forValue(value)"
        );

        // and controller should invoke TestEnumSpec.fromString for query params
        assertFileContains(
                Paths.get(outputPath + "/src/main/kotlin/org/openapitools/api/DefaultApiController.kt"),
                "TestEnumSpec.fromString"
        );
    }

}

