import javax.validation.constraints.Max
import javax.validation.constraints.Min
import javax.validation.constraints.NotNull
import javax.validation.constraints.Pattern
import javax.validation.constraints.Size
import javax.validation.Valid
import io.swagger.v3.oas.annotations.media.Schema

/**
* 
* Values: ABC,DEF,GHK
*/
enum class TestEnumSpec(@get:JsonValue val value: kotlin.String) {

    ABC("abc"),
    DEF("def"),
    GHK("ghk");

    companion object {
        @JvmStatic
        @JsonCreator
        fun forValue(value: kotlin.String): TestEnumSpec {
                return values().first{it -> it.value == value}
        }

        /**
         * Used by Spring's default String-to-Enum conversion in query/path params.
         */
        @JvmStatic
        fun fromString(value: kotlin.String): TestEnumSpec = forValue(value)
    }
}

